const BLOCK_PATTERNS = [
    /union\s+select/i,
    /;\s*drop\s+/i,
    /--\s*$/,
    /<script[^>]*>/i,
    /javascript:/i,
    /onerror\s*=/i,
    /\.\.\//,           // path traversal
    /%2e%2e%2f/i,       // encoded path traversal
];

module.exports = function wafMiddleware(req, res, next) {
    const check = [
        req.url,
        JSON.stringify(req.query || {}),
        JSON.stringify(req.body || {}),
    ].join(' ');

    for (const pattern of BLOCK_PATTERNS) {
        if (pattern.test(check)) {
            console.warn(`[WAF] Blocked request: ${req.method} ${req.url} — matched ${pattern}`);
            return res.status(403).json({ error: 'Request blocked by security filter' });
        }
    }

    next();
};

